[HttpGet]
public List<User> GetUser([FromQuery(Name="email")] string email)
{
    using (var conn = new SqlConnection("server=localhost;user id=root;password=<PASSWORD>;database=db")) {
        var sql = "select * from users where email=@email";
        var cmd = new SqlCommand(sql, conn);
        cmd.Parameters.AddWithValue("@email", email);

        try{
            conn.Open();

            using (var reader = command.ExecuteReader())
                while (reader.Read()) {
                    resultList.Add(new User()
                        .WithId(reader["id"].ToString())
                        .WithName(reader["name"].ToString())
                        .WithEmail(reader["email"].ToString()));
            }

        }catch (SqlException e){
           // log here
        } finally{
            conn.Close();
        }
    return resultList;
}
